/* 感谢食用小狗爱的美化，接下来请阅读一下食用须知！！
    插图和引言都可以自定义的，插图使用猫箱外链导入图片后找到有小狗爪🐾🐾的代码就可以自行更换啦！ 
    猫箱链接：https://catbox.moe/ 
*/

/* --- 字体导入 --- */
@import url("https://fontsapi.zeoseven.com/256/main/result.css"); /* 汇文明朝体 */
@import url("https://fontsapi.zeoseven.com/237/main/result.css"); /* 香萃打字机体 */
/* --- 全局与特殊字体设置 --- */

/* 1. 全局字体设置为“汇文明朝体” */
body, 
#chat, 
.text_pole, 
textarea, 
select, 
.menu_button, 
h3, 
h4,
code,
.mes .mes_text {
    font-family: 'Huiwen-mincho', "汇文明朝体", sans-serif !important; 
}

.mes .ch_name .name_text,
#ch_name1,             
#character_name_pole    
{
    font-family: 'XiangcuiDazijitiW15', "香萃打字机体", monospace !important;
}


:root {
--white50a:  #e0e4e8;
}


.mes {
    padding: 0;
    margin-bottom: 30px;
    width: 100%;
}

.mes .mes_block {
    position: relative;
    width: 100%;
    min-height: auto;
    margin-left: 0;
    padding: 20px 15px;
    background-color: #ffffff;
    border-radius: 12px;
    box-shadow: 
        0 2px 8px rgba(0, 0, 0, 0.08),
        0 1px 4px rgba(0, 0, 0, 0.04),
        0 0 0 1px rgba(0, 0, 0, 0.02);
    border: 1px solid rgba(255, 255, 255, 0.8);
    margin-bottom: 30px; /* <--- 新增这一行来控制卡片间距 */
}

.mes .avatar {
    display: block; 
    position: absolute;
    z-index: 10;
    top: 20px;
    left: 10px;
    width: 120px;
    height: 160px;
    border: none;
    border-radius: 8px; 
    overflow: hidden; 
    padding: 0;
    background: none;
    box-shadow: 
        inset 0 0 1px 1px rgba(255, 255, 255, 0.8),
        0px 2px 8px rgba(0, 0, 0, 0.1); 
}
.mes .avatar img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    border-radius: 8px; /* 内部图片也需要圆角 */
}

.mes .avatar::after {
    content: "VOLUME Ⅰ";

    position: absolute;
    bottom: 0;
    left: 0;
    width: 100%;
    height: 30px;
    background-color: #F8F9FA; 

    -webkit-backdrop-filter: none;
    backdrop-filter: none;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #A0AEC0; 

    font-family: "Georgia", "Times New Roman", serif;
    font-size: 11px;
    font-weight: 600;
    letter-spacing: 2px;
    text-transform: uppercase;
    text-shadow: 1px 1px 1px rgba(255, 255, 255, 0.7); 
}

.mes[is_user="true"] .avatar::after {
    content: "Bookmark";
    background-color: #EBF1F8;
    color: #A0AEC0; 

    font-size: 11px;
    letter-spacing: 2px;
    text-shadow: 1px 1px 1px rgba(255, 255, 255, 0.6);
}

.mes .avatar img {
    position: relative;
    z-index: 1;
}

.mes .avatar::after {
    z-index: 10;
}


.mes .ch_name {
    position: relative;
    z-index: 2; 
    padding: 0 0 20px 130px; 
    min-height: 160px;
    display: block;
}

.mes .ch_name .name_text {
    font-size: 1.3em;
    font-weight: 600;
    color: #333;
}
.mes .ch_name .name_text::before { content: '本次阅读：《'; font-weight: normal; color: #888; }
.mes .ch_name .name_text::after { content: ' 》'; font-weight: normal; color: #888; }

/* --- 信息 --- */
.mes .ch_name::after {
    content: '现代/爱情/文艺/2025-10-23 (东京)\A最佳主角x并非小狗\A章节：未完待续\A……汪！૮ >⸝⸝⸝⸝< ა';
    white-space: pre;
    display: block;
    margin-top: 10px;
    font-size: 12px;
    line-height: 1.8;
    color: #777;
    letter-spacing: 1px;
}


.mes .mes_text {
    position: relative;
    width: 100%;
    padding: 225px 0px 10px 0px;
    overflow-wrap: break-word; 
    margin: 0px;
    border: none;
    text-align: left;
    line-height: 2;
    letter-spacing: 1px;
    color: #444;
}


/*  🐾🐾这里是char的引言部分！可以自改 \A是换行符 🐾🐾 */
.mes .mes_text::before {
    /* --- 在这里为【角色】自定义引言 --- */
    content: "\A Then we kissed, like two mirrors of pain,\A peeling off little by little the silver filaments of bitterness from each other's bones. ";
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    display: block;
    white-space: pre-wrap;
    font-family: "Georgia", "Times New Roman", serif;
    font-style: italic;
    font-size: 0.8em;
    line-height: 1.6;
    color: #667;
}

/*  🐾🐾这里是user的引言部分！可以自改 \A是换行符 🐾🐾 */
.mes[is_user="true"] .mes_text::before {
    /* --- 在这里为【用户】自定义引言 --- */
    content: "\A To see the world, things dangerous to come to, to see behind walls, draw closer, to find each other and to feel. That is the purpose of life. ";
}


/* ---横向图片--- */
.mes .mes_text::after {
/*  🐾🐾这里是char的图片部分！可以自改🐾🐾 */
    content: ''; 
    background-image: url('https://files.catbox.moe/gicy73.png');
    position: absolute;
    top: 80px; 
    left: 0;
    width: 100%;
    height: 120px; /* 图片的高度 */
    background-size: cover;
    background-position: center;
    border-radius: 4px; /* 圆角 */
    box-shadow: 0 4px 4px rgba(0, 0, 0, 0.1);
}

/* 为【用户】自定义不同的图片 */
.mes[is_user="true"] .mes_text::after {
/*  🐾🐾这里是user的图片部分！可以自改  🐾🐾 */
    background-image: url('https://files.catbox.moe/gicy73.png');
}


.mes .mes_timer,
.mes .mesIDDisplay,
.mes .tokenCounterDisplay {
    display: block !important; position: absolute; z-index: 10;
    background: none !important; padding: 0 !important; color: inherit;
    border: none !important; border-radius: 0 !important; box-shadow: none !important;
    overflow: visible;
}

.mes .mes_timer, .mes .mes_timer::before, .mes .mes_timer::after,
.mes .mesIDDisplay, .mes .mesIDDisplay::before, .mes .mesIDDisplay::after,
.mes .tokenCounterDisplay, .mes .tokenCounterDisplay::after {
    font-family: 'Huiwen-mincho', "汇文明朝体", sans-serif;
    font-style: normal;
    font-size: 12px;
    font-weight: normal;
    color: #a0aec0; 
}

.mes:not([is_user="true"]) .mes_timer::before {
    content: "“限时 ";
}
.mes:not([is_user="true"]) .mes_timer::after {
    content: " 秒猜谜：小小狗走了 ";
}
.mes:not([is_user="true"]) .mesIDDisplay::after {
    content: " 步，咬了 ";
}
.mes:not([is_user="true"]) .tokenCounterDisplay::after {
    content: " 口。…猜到了吗？”";
}
.mes[is_user="true"] .mes_timer {
    display: none !important;
}
.mes[is_user="true"] .mes_timer::before,
.mes[is_user="true"] .mes_timer::after {
    content: "" !important;
}
.mes[is_user="true"] .mesIDDisplay::before {
    content: "“小小狗走了 ";
}
.mes[is_user="true"] .mesIDDisplay::after {
    content: " 步，咬了 ";
}
.mes[is_user="true"] .tokenCounterDisplay::after {
    content: " 口。…是剪刀！”";
}

.mes:not([is_user="true"]) .mes_timer {
    top: 140px;
    left: 140px;
}
.mes:not([is_user="true"]) .mesIDDisplay {
    top: 140px;
    left: 315px;
}
.mes:not([is_user="true"]) .tokenCounterDisplay {
    top: 160px;
    left: 140px;
}

.mes[is_user="true"] .mesIDDisplay {
    top: 145px;
    left: 140px; 
}
.mes[is_user="true"] .tokenCounterDisplay {
    top: 145px;
    left: 280px; 
}

.mes_text b, .mes_text strong {
    color: #000; 
    font-weight: 700; 
    text-shadow: 0 0 1px rgba(0, 0, 0, 0.1);
}

.mes_text i, .mes_text em {
    display: inline;
    position: relative; 
    -webkit-box-decoration-break: clone;
    box-decoration-break: clone;
    background: none;
    quotes: none;
    padding: 0.1em 0.2em 0.3em 0.2em;
    margin: 0;
    border-bottom: 1px solid; 
    border-image-source: linear-gradient(
        to right, 
        rgba(180, 190, 205, 0.8) 0%, /* 起始颜色 */
        rgba(180, 190, 205, 0) 80%  /* 在80%处变为透明 */
    );
    border-image-slice: 1; 

    color: #A0AEC0;
    font-style: italic;
    vertical-align: initial;
}

.mes_text code,
.mes_text blockquote {
    display: inline-block; 
    position: relative;
    padding: 0.2em 0.6em; 
    margin: 0 0.2em; 
    background: transparent;
    border: 1px solid rgba(0, 0, 0, 0.04); 
    border-radius: 6px; 
    box-shadow: 
        inset 0 0 2px rgba(255, 255, 255, 1),
        0 1px 2px rgba(0, 0, 0, 0.05); 
}

.mes_text code {
    color: #5A67D8; 
    font-family: "SF Mono", "Menlo", "Monaco", monospace;
    font-size: 0.9em; 
}

.mes_text s, .mes_text del {
    color: #999; 
    text-decoration-color: #AAAAAA; 
}

.mes_text q {
    display: inline;
    position: relative;
    -webkit-box-decoration-break: clone;
    box-decoration-break: clone;
    padding: 0.2em 0.6em;
    margin: 0;
    color: #555;
    quotes: none;
    line-height: 2;
    border-radius: 10px;
    background-image: 
        radial-gradient(
            ellipse at center,
            rgba(190, 210, 235, 0.25) 0%,
            rgba(210, 225, 240, 0) 60%
        ),
        linear-gradient(to top, #FFFFFF, #FFFFFF);

    background-repeat: no-repeat, no-repeat; 
    background-position: center, center; 
    background-size: 100% 100%, 100% 100%;

    box-shadow: 
        0 2px 5px rgba(0, 0, 0, 0.04),
        0 0 0 1px rgba(0, 0, 0, 0.05),
        inset 0 0 0 1px rgba(255, 255, 255, 1),
        inset 1px 1px 2px rgba(0, 0, 0, 0.08);
}

